var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"과연, 오지만디아스.","JPN":"さすがはオジマンディアス。","ENG":"As expected, Ozymandias.","TWN":"果然，奧茲曼迪亞斯。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 무대에서 제가 마주한 상대 중에는 가장 방어가 견고하군요.","JPN":"この舞台で私が出会ったどの相手よりも防御が堅いです。","ENG":"Your defense is the strongest I've faced on this performance.","TWN":"在這個舞台上，我遇到的對手中，你的防禦最為堅固。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"순식간에 지면을 내려쳐서……?","JPN":"一瞬で地面を叩きつけて……？","ENG":"She suddenly hit the ground...?","TWN":"一瞬間震碎地面……？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"설마, 이건……?","JPN":"まさか、これって……？","ENG":"Is this...?","TWN":"難道是……？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요.","JPN":"ええ。","ENG":"It is.","TWN":"沒錯。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 날 경기를 통해 당신 약점은 이미 만천하에 공개되어 있답니다.","JPN":"あの日の試合を通じて、あなたの弱点はすでに剥き出しも同然となりました。","ENG":"Your weakness was revealed to the world through that game.","TWN":"那天的比賽已經把你的弱點暴露無遺了。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"두 다리가 지면에 닿아 있지 않으면, 그 빈틈없는 방어에도 구멍이 생기죠.","JPN":"両足が地面についていなければ、あの抜かりない防御にも隙が生じる。","ENG":"If both your legs aren't on the ground, even your defense can't hold.","TWN":"如果雙腳不著地，即使是無懈可擊的防禦也會出現破綻。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하! 정말이지! 아무래도 앝보인 모양이네!","JPN":"は！　まったく！　どうやらなめられちゃったようね！","ENG":"Ha! You've got to be kidding me! Seems like I'm being underestimated!","TWN":"哈！真是的！看來是被小瞧了啊！"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"미안하지만, 이건 건틀렛이 아니라고? 이것저것 사정 봐줄 필요는 없겠지?","JPN":"悪いけど、これはガントレットじゃないのよ？　容赦する必要なんてないわよね？","ENG":"Sorry to burst your bubble, but this isn't the Gauntlet. So, I don't need to hold back.","TWN":"抱歉，這可不是聖鎧吧？沒必要顧慮那麼多吧？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그럼, 진심으로 간다……!!","JPN":"だから、本気で行くわ……！！","ENG":"All right! Let's do this...!!","TWN":"那麼，要來了……！！"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"예상대로.","JPN":"予想どおり。","ENG":"As expected.","TWN":"果然不出所料。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무구를 개방할 생각이로군요.","JPN":"武具を開放するつもりですね。","ENG":"You are about to unleash your Armament.","TWN":"你打算開放武具了。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……えっ？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"처음부터 전력을 다하지 않은 건, 아마도 상대를 가늠하며 승부를 즐겨볼 셈이었겠죠.","JPN":"最初から本気を出していなかったのは、おそらく相手を見極めながら勝負を楽しむつもりだったのでしょう。","ENG":"The reason you didn't give your best from the beginning was because you wanted to gauge your opponent and enjoy the fight.","TWN":"一開始沒有全力以赴，大概是想在衡量對手的同時享受比賽吧。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당신 말대로 이건 건틀렛이 아니에요.","JPN":"ですが、あなたの言ったとおり、これはガントレットではありません。","ENG":"But like you said, this isn't the Gauntlet.","TWN":"但正如你所說的，這不是聖鎧。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니까 싸움을 단순히 승부 감각으로 임하는 당신의 패배입니다.","JPN":"命がけの戦いに、遊び感覚で臨んでしまったあなたの負けです。","ENG":"So, your simply approaching this fight with a sense of victory is the reason you will lose.","TWN":"所以，單純地以勝負欲對待戰鬥，這便是你的敗因。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그건……? 내 검을……?","JPN":"それは……？　私の剣……？","ENG":"Is this... my sword…?","TWN":"那個是……？我的劍……？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"특이한 검이지만, 사용법은 충분할 정도로 관람했어요.","JPN":"変わった剣ですが、使い方なら十分見させてもらいました。","ENG":"An unusual sword, but I have seen enough to know how to use it.","TWN":"雖然是把奇特的劍，但我已經看夠了它的用法。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면……!","JPN":"ならば……！","ENG":"Then...!","TWN":"這樣的話……！"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};